import numpy as np

# f(x, y) = x^2 + 3*x*y . Partials: df/dx = 2x+3y, df/dy = 3x
def grad(x, y):
    return np.array([2*x + 3*y, 3*x])

print(grad(1.0, 2.0))   # [8. 3.]
# step against the gradient to reduce f

def f(x):
    return x**3 - 2*x

def numeric_deriv(f, x, h=1e-6):
    return (f(x + h) - f(x - h)) / (2 * h)   # central diff

print(round(numeric_deriv(f, 2.0), 4))   # ~10.0
# true derivative 3x^2 - 2 = 3*4 - 2 = 10
